const items = $input.all();
const results = [];
let currentEmployee = null;

function excelDateToString(serial) {
  if (!serial || isNaN(serial)) return String(serial);
  const date = new Date((serial - 25569) * 86400 * 1000);
  return date.toISOString().split('T')[0];
}

function extractTime(str) {
  if (!str || str.trim() === '') return 'MISSING';
  const s = String(str).trim();
  const match = s.match(/(\d{1,2})\s*:\s*(\d{2})\s*$/);
  if (match) {
    return `${match[1].padStart(2,'0')}:${match[2]}`;
  }
  return 'MISSING';
}

for (const item of items) {
  const row = item.json;
  const firstCol = row['Growify Digital LLP'];
  const firstStr = String(firstCol || '').trim();

  if (firstStr.match(/^GD\d+/)) {
    currentEmployee = {
      employeeId: firstStr,
      name: String(row['__EMPTY'] || '').trim()
    };
    continue;
  }

  if (!currentEmployee) continue;

  if (!firstCol || isNaN(Number(firstCol))) continue;

  const dateRaw = row['__EMPTY'];
  const session1 = String(row['__EMPTY_1'] || '').trim();
  const inTime = String(row['__EMPTY_3'] || '').trim();
  const outTime = String(row['__EMPTY_4'] || '').trim();

  if (['OFF', 'LC'].includes(session1)) continue;

  if (!inTime || inTime === '') continue;

  const checkInTime = extractTime(inTime);
  if (checkInTime === 'MISSING') continue;

  const checkOutTime = extractTime(outTime);

  const dateStr = excelDateToString(dateRaw);

  let lateFlag = 'NO';
  const [hour, minute] = checkInTime.split(':').map(Number);
  if (!isNaN(hour) && (hour > 11 || (hour === 11 && minute > 0))) {
    lateFlag = 'YES';
  }

  results.push({
    json: {
      employeeId: currentEmployee.employeeId,
      name: currentEmployee.name,
      date: dateStr,
      checkIn: checkInTime,
      checkOut: checkOutTime,
      lateFlag: lateFlag
    }
  });
}

return results;

const items = $input.all();

const lateItems = items.filter(item => item.json['Late Flag'] === 'YES');

const results = [];

for (const item of lateItems) {
  results.push({
    json: {
      employeeId: item.json['Employee ID'],
      name: item.json['Name'],
      date: item.json['Date'],
      checkIn: item.json['Check-In'],
      checkOut: item.json['Check-Out'],
      lateFlag: item.json['Late Flag'],
      month: item.json['Date'].substring(0, 7)
    }
  });
}

return results;

const items = $input.all();

const counter = {};

for (const item of items) {
  const { employeeId, name, month } = item.json;
  const key = `${employeeId}_${month}`;

  if (!counter[key]) {
    counter[key] = {
      employeeId,
      name,
      monthYear: month,
      monthlyLateCount: 0,
      lastWarningDate: ''
    };
  }
  counter[key].monthlyLateCount += 1;
  counter[key].lastWarningDate = item.json.date;
}

const results = Object.values(counter).map(emp => ({
  json: {
    employeeId: emp.employeeId,
    name: emp.name,
    monthlyLateCount: emp.monthlyLateCount,
    lastWarningDate: emp.lastWarningDate,
    monthYear: emp.monthYear,
    strikeLevel: emp.monthlyLateCount >= 3 ? 3 : emp.monthlyLateCount
  }
}));

return results;

